import { test, expect } from '@playwright/test';

const BASE_URL = process.env.BASE_URL ?? 'http://localhost:3000';
const HEALTH_ENDPOINT = '/api/health';

interface HealthResponse {
  status: string;
  ollama: boolean;
  chromadb: boolean;
  llm_model: string;
}

test.describe('Happy Path - Health Check API', () => {
  // SCENARIO_ID: 488a9eda-1e65-4951-8adb-cf6cd128ad52
  test('Health check returns ok when all dependencies are healthy', async ({ request }) => {
    const response = await request.get(`${BASE_URL}${HEALTH_ENDPOINT}`);

    expect(response.status()).toBe(200);

    const body: HealthResponse = await response.json();
    expect(body.status).toBe('ok');
    expect(body.ollama).toBe(true);
    expect(body.chromadb).toBe(true);
    expect(typeof body.llm_model).toBe('string');
    expect(body.llm_model.length).toBeGreaterThan(0);
  });

  // SCENARIO_ID: e1e3d09b-45c3-4dd6-8426-5d5ca2eb94ca
  test('Health check verifies Ollama endpoint returns 200 status specifically', async ({ request }) => {
    // Note: This test requires Ollama mock configured to return 200 for first request
    // and 201 for second request to validate status code specificity

    // First request - Ollama returns 200 OK
    const responseOk = await request.get(`${BASE_URL}${HEALTH_ENDPOINT}`);
    const bodyOk: HealthResponse = await responseOk.json();
    expect(bodyOk.ollama).toBe(true);

    // Note: For full test coverage, configure Ollama mock to return 201
    // Then verify ollama would be false for non-200 responses
    // This requires separate test environment configuration
  });
});

