});

test.describe('Edge Case - Health Check API', () => {
  // SCENARIO_ID: f244d55a-6e5d-46f6-9ab0-798e4eea27ce
  test('Health check handles Ollama request timeout', async ({ request }) => {
    // Preconditions: Ollama mock with 5 second delay on /api/tags endpoint
    // The health endpoint has a 3 second timeout for Ollama checks

    const response = await request.get(`${BASE_URL}${HEALTH_ENDPOINT}`);

    expect(response.status()).toBe(200);

    const body: HealthResponse = await response.json();
    expect(body.status).toBe('degraded');
    expect(body.ollama).toBe(false);
  });

  // SCENARIO_ID: 6208d650-e613-4697-914e-38e56af5abb1
  test('Health check returns degraded when all dependencies are down', async ({ request }) => {
    // Preconditions: Both Ollama and ChromaDB are unavailable

    const response = await request.get(`${BASE_URL}${HEALTH_ENDPOINT}`);

    expect(response.status()).toBe(200);

    const body: HealthResponse = await response.json();
    expect(body.status).toBe('degraded');
    expect(body.ollama).toBe(false);
    expect(body.chromadb).toBe(false);
  });

  // SCENARIO_ID: a69ef750-7d9b-490f-ae02-db04fa6858d5
  test('Health check handles concurrent requests without race conditions', async ({ request }) => {
    const concurrentRequests = 10;
    const requests = Array(concurrentRequests)
      .fill(null)
      .map(() => request.get(`${BASE_URL}${HEALTH_ENDPOINT}`));

    const responses = await Promise.all(requests);

    // Verify all responses have status code 200
    for (const response of responses) {
      expect(response.status()).toBe(200);
    }

    // Parse all response bodies
    const bodies: HealthResponse[] = await Promise.all(
      responses.map((response) => response.json())
    );

    // Verify all responses have consistent status
    const statuses = bodies.map((body) => body.status);
    const uniqueStatuses = new Set(statuses);
    expect(uniqueStatuses.size).toBe(1);

    // Verify all responses have matching llm_model value
    const llmModels = bodies.map((body) => body.llm_model);
    const uniqueModels = new Set(llmModels);
    expect(uniqueModels.size).toBe(1);
    expect(typeof bodies[0].llm_model).toBe('string');
    expect(bodies[0].llm_model.length).toBeGreaterThan(0);
  });

  // SCENARIO_ID: cecdce66-ea3d-4314-9dd3-e4d7e7080338
  test('Health check handles malformed response from Ollama', async ({ request }) => {
    // Preconditions: Ollama mock returns 500 Internal Server Error or malformed JSON

    const response = await request.get(`${BASE_URL}${HEALTH_ENDPOINT}`);

    expect(response.status()).toBe(200);

    const body: HealthResponse = await response.json();
    expect(body.status).toBe('degraded');
    expect(body.ollama).toBe(false);
  });
});

test.describe('Security - Health Check API', () => {
  // SCENARIO_ID: de953c74-c36c-4268-b386-3f09a211d702
  test('Health check does not expose sensitive configuration values', async ({ request }) => {
    const response = await request.get(`${BASE_URL}${HEALTH_ENDPOINT}`);

    expect(response.status()).toBe(200);

    const body = await response.json();

    // Verify response contains only allowed fields
    const allowedFields = ['status', 'ollama', 'chromadb', 'llm_model'];
    const responseFields = Object.keys(body);

    for (const field of responseFields) {
      expect(allowedFields).toContain(field);
    }

    // Verify response does not contain OLLAMA_BASE_URL value
    const bodyString = JSON.stringify(body);
    expect(bodyString).not.toContain('http://');
    expect(bodyString).not.toContain('https://');
    expect(bodyString).not.toContain('localhost');

    // Verify response does not contain password or secret fields
    expect(body).not.toHaveProperty('password');
    expect(body).not.toHaveProperty('secret');
    expect(body).not.toHaveProperty('api_key');
    expect(body).not.toHaveProperty('apiKey');
    expect(body).not.toHaveProperty('OLLAMA_BASE_URL');
    expect(body).not.toHaveProperty('DATABASE_URL');
  });
});

